# 1. Insert Node - O(log N) average
def insert(root, key):
    if root is None:
        return TreeNode(key)
    if key < root.val:
        root.left = insert(root.left, key)
    else:
        root.right = insert(root.right, key)
    return root

# 2. Search Key - O(log N) average
def search(root, key):
    if root is None or root.val == key:
        return root
    if key < root.val:
        return search(root.left, key)
    return search(root.right, key)

# 3. Find Minimum Node (Leftmost leaf) - O(log N) average
def min_value_node(node):
    current = node
    while current.left is not None:
        current = current.left
    return current

# 4. Delete Node - O(log N) average
def delete_node(root, key):
    if root is None:
        return root
    if key < root.val:
        root.left = delete_node(root.left, key)
    elif key > root.val:
        root.right = delete_node(root.right, key)
    else:
        # Node with only one child or no child
        if root.left is None:
            return root.right
        elif root.right is None:
            return root.left
        # Node with two children: Get the inorder successor
        temp = min_value_node(root.right)
        root.val = temp.val
        root.right = delete_node(root.right, temp.val)
    return root

# Run operations
bst = TreeNode(50)
insert(bst, 30)
insert(bst, 70)

found = search(bst, 30)
print(found.val if found else "Not Found") # 30
delete_node(bst, 30)
print(search(bst, 30))                     # None (Successfully Deleted)
